class WebSocketClient:
    def __init__(self, conn, addr):
        self.conn = conn
        self.addr = addr
        self.connected = True

    def read_frame(self):
        try:
            header = self.conn.recv(2)
            if len(header) < 2:
                self.connected = False
                return None

            fin = (header[0] >> 7) & 1
            opcode = header[0] & 0x0F
            masked = (header[1] >> 7) & 1
            payload_len = header[1] & 0x7F

            if opcode == 0x8:
                self.connected = False
                return None

            if payload_len == 126:
                data = self.conn.recv(2)
                payload_len = struct.unpack(">H", data)[0]
            elif payload_len == 127:
                data = self.conn.recv(8)
                payload_len = struct.unpack(">Q", data)[0]

            mask_key = None
            if masked:
                mask_key = self.conn.recv(4)

            payload = b""
            while len(payload) < payload_len:
                chunk = self.conn.recv(payload_len - len(payload))
                if not chunk:
                    self.connected = False
                    return None
                payload += chunk

            if mask_key:
                payload = bytes(b ^ mask_key[i % 4] for i, b in enumerate(payload))

            if opcode == 0x9:
                self.send_frame(payload, 0xA)
                return self.read_frame()

            return payload.decode("utf-8")
        except OSError:
            self.connected = False
            return None

    def send_frame(self, data, opcode=0x1):
        try:
            if isinstance(data, str):
                data = data.encode("utf-8")

            frame = bytearray()
            frame.append(0x80 | opcode)

            length = len(data)
            if length < 126:
                frame.append(length)
            elif length < 65536:
                frame.append(126)
                frame.extend(struct.pack(">H", length))
            else:
                frame.append(127)
                frame.extend(struct.pack(">Q", length))

            frame.extend(data)
            self.conn.send(frame)
            return True
        except OSError:
            self.connected = False
            return False

    def send_json(self, obj):
        return self.send_frame(json.dumps(obj))

    def close(self):
        try:
            self.send_frame(b"", 0x8)
            self.conn.close()
        except Exception:
            pass
        self.connected = False


class IoTDevice:
    def __init__(self):
        self.led = machine.Pin(2, machine.Pin.OUT)
        self.relay_pins = {}
        self.state = {
            "power": False,
            "led": False,
            "brightness": 0,
            "temperature": 0.0,
            "humidity": 0.0,
            "uptime": 0,
            "device_name": "ESP32-IoT",
            "firmware_version": "1.0.0",
        }
        self.pwm_led = None
        try:
            self.pwm_led = machine.PWM(machine.Pin(2), freq=1000, duty=0)
        except Exception:
            pass

    def turn_on(self):
        self.state["power"] = True
        self.state["led"] = True
        self.led.value(1)
        if self.pwm_led:
            self.pwm_led.duty(int(self.state["brightness"] / 100 * 1023))
        return {"status": "ok", "action": "turn_on", "state": self.state}

    def turn_off(self):
        self.state["power"] = False
        self.state["led"] = False
        self.led.value(0)
        if self.pwm_led:
            self.pwm_led.duty(0)
        return {"status": "ok", "action": "turn_off", "state": self.state}

    def set_brightness(self, level):
        level = max(0, min(100, int(level)))
        self.state["brightness"] = level
        if self.pwm_led and self.state["power"]:
            self.pwm_led.duty(int(level / 100 * 1023))
        return {"status": "ok", "action": "set_brightness", "brightness": level, "state": self.state}

    def toggle(self):
        if self.state["power"]:
            return self.turn_off()
        else:
            return self.turn_on()

    def get_status(self):
        self.state["uptime"] = time.ticks_ms() // 1000
        try:
            import esp32
            self.state["temperature"] = esp32.raw_temperature()
        except Exception:
            self.state["temperature"] = 25.0
        return {"status": "ok", "action": "status", "state": self.state}

    def set_relay(self, relay_id, value):
        pin_num = {0: 12, 1: 13, 2: 14, 3: 15}.get(relay_id)
        if pin_num is None:
            return {"status": "error", "message": "Invalid relay ID"}
        if relay_id not in self.relay_pins:
            self.relay_pins[relay_id] = machine.Pin(pin_num, machine.Pin.OUT)
        self.relay_pins[relay_id].value(1 if value else 0)
        return {"status": "ok", "action": "set_relay", "relay_id": relay_id, "value": value}

    def handle_command(self, command):
        try:
            if isinstance(command, str):
                command = json.loads(command)

            action = command.get("action", "")

            if action == "turn_on":
                return self.turn_on()
            elif action == "turn_off":
                return self.turn_off()
            elif action == "toggle":
                return self.toggle()
            elif action == "set_brightness":
                level = command.get("value", 50)
                return self.set_brightness(level)
            elif action == "status" or action == "get_status":
                return self.get_status()
            elif action == "set_relay":
                relay_id = command.get("relay_id", 0)
                value = command.get("value", False)
                return self.set_relay(relay_id, value)
            elif action == "ping":
                return {"status": "ok", "action": "pong", "timestamp": time.ticks_ms()}
            elif action == "restart":
                return {"status": "ok", "action": "restart", "message": "Restarting in 2 seconds..."}
            else:
                return {"status": "error", "message": "Unknown action: {}".format(action)}
        except (ValueError, KeyError) as e:
            return {"status": "error", "message": "Invalid command: {}".format(str(e))}


class WebSocketServer:
    WEBSOCKET_MAGIC = "258EAFA5-E914-47DA-95CA-5AB5DC799B07"

    def __init__(self, host="0.0.0.0", port=8080, max_clients=4):
        self.host = host
        self.port = port
        self.max_clients = max_clients
        self.clients = []
        self.device = IoTDevice()
        self.running = False
        self.server_socket = None

    def _generate_accept_key(self, key):
        combined = key.strip() + self.WEBSOCKET_MAGIC
        sha1_hash = hashlib.sha1(combined.encode()).digest()
        return binascii.b2a_base64(sha1_hash).decode().strip()

